class SubmitTestDataWireMockTest extends com.httpbinlivetestingapi.base.WireMockBaseTest {

    private PostApiClient client;

    @BeforeEach
    void init() {
        client = new PostApiClient(wireMockSpec);
    }

    @Test
    @DisplayName("POST /post — 200 response matches HttpbinResponse JSON schema")
    void submitTestData_returns200_matchesSchema() {
        String responseBody = "{"
                + "\"url\": \"https://httpbin.org/post\","
                + "\"json\": {\"environment\": \"staging\", \"featuresEnabled\": true}"
                + "}";

        stubFor(WireMock.post(WireMock.urlEqualTo("/post"))
                .withHeader("X-Test-Header", WireMock.matching(".+"))
                .willReturn(WireMock.aResponse()
                        .withStatus(200)
                        .withHeader("Content-Type", "application/json")
                        .withBody(responseBody)));

        MetricDetailsDto metrics = MetricDetailsDto.builder()
                .testsCount(42)
                .passRate(98.5)
                .build();

        TestPayloadInputDto payload = TestPayloadInputDto.builder()
                .environment("staging")
                .featuresEnabled(true)
                .metrics(metrics)
                .build();

        Response response = client.submitTestData(payload, "test-header-value");

        assertThat(response.getStatusCode(), org.hamcrest.Matchers.equalTo(200));
        assertThat(response.getBody(), notNullValue());
        assertThat(response.asString(), matchesJsonSchemaInClasspath("schemas/httpbin_response_schema.json"));
    }

    @Test
    @DisplayName("POST /post — response url field is populated")
    void submitTestData_responseContainsUrl() {
        String responseBody = "{"
                + "\"url\": \"https://httpbin.org/post\","
                + "\"json\": {\"environment\": \"production\", \"featuresEnabled\": false}"
                + "}";

        stubFor(WireMock.post(WireMock.urlEqualTo("/post"))
                .withHeader("X-Test-Header", WireMock.equalTo("my-header"))
                .willReturn(WireMock.aResponse()
                        .withStatus(200)
                        .withHeader("Content-Type", "application/json")
                        .withBody(responseBody)));

        MetricDetailsDto metrics = MetricDetailsDto.builder()
                .testsCount(10)
                .passRate(75.0)
                .build();

        TestPayloadInputDto payload = TestPayloadInputDto.builder()
                .environment("production")
                .featuresEnabled(false)
                .metrics(metrics)
                .build();

        Response response = client.submitTestData(payload, "my-header");

        assertThat(response.getStatusCode(), org.hamcrest.Matchers.equalTo(200));
        assertThat(response.jsonPath().getString("url"), org.hamcrest.Matchers.equalTo("https://httpbin.org/post"));
    }

    @Test
    @DisplayName("POST /post — json body echoed back in response")
    void submitTestData_jsonEchoedInResponse() {
        String responseBody = "{"
                + "\"url\": \"https://httpbin.org/post\","
                + "\"json\": {\"environment\": \"dev\", \"featuresEnabled\": true, \"metrics\": {\"testsCount\": 5, \"passRate\": 60.0}}"
                + "}";

        stubFor(WireMock.post(WireMock.urlEqualTo("/post"))
                .willReturn(WireMock.aResponse()
                        .withStatus(200)
                        .withHeader("Content-Type", "application/json")
                        .withBody(responseBody)));

        MetricDetailsDto metrics = MetricDetailsDto.builder()
                .testsCount(5)
                .passRate(60.0)
                .build();

        TestPayloadInputDto payload = TestPayloadInputDto.builder()
                .environment("dev")
                .featuresEnabled(true)
                .metrics(metrics)
                .build();

        Response response = client.submitTestData(payload, "dev-header");

        assertThat(response.getStatusCode(), org.hamcrest.Matchers.equalTo(200));
        assertThat(response.jsonPath().getString("json.environment"), org.hamcrest.Matchers.equalTo("dev"));
    }
}

