import static org.hamcrest.MatcherAssert.assertThat;
import static org.hamcrest.Matchers.equalTo;
import static org.hamcrest.Matchers.greaterThanOrEqualTo;

class HttpbinNegativeTest extends com.httpbinlivetestingapi.base.WireMockBaseTest {

    private PostApiClient client;

    @BeforeEach
    void init() {
        client = new PostApiClient(wireMockSpec);
    }

    @Test
    @DisplayName("POST /post — missing required header returns 400")
    void submitTestData_missingRequiredHeader_returns400() {
        stubFor(WireMock.post(WireMock.urlEqualTo("/post"))
                .withHeader("X-Test-Header", WireMock.absent())
                .willReturn(WireMock.aResponse()
                        .withStatus(400)
                        .withHeader("Content-Type", "application/json")
                        .withBody("{\"error\": \"Missing required header: X-Test-Header\"}")));

        MetricDetailsDto metrics = MetricDetailsDto.builder()
                .testsCount(1)
                .passRate(100.0)
                .build();

        TestPayloadInputDto payload = TestPayloadInputDto.builder()
                .environment("test")
                .featuresEnabled(true)
                .metrics(metrics)
                .build();

        // Simulate missing header by passing empty string — stub matches absent header
        Response response = client.submitTestData(payload, "");

        // WireMock will return 400 for absent header; if header is present but empty,
        // the default stub returns 404 — both are error codes
        assertThat(response.getStatusCode(), greaterThanOrEqualTo(400));
    }

    @Test
    @DisplayName("GET /get — unknown path returns 404")
    void fetchTestData_unknownPath_returns404() {
        stubFor(WireMock.get(WireMock.urlPathEqualTo("/get/unknown"))
                .willReturn(WireMock.aResponse()
                        .withStatus(404)
                        .withHeader("Content-Type", "application/json")
                        .withBody("{\"error\": \"Not Found\"}")));

        // No stub for /get — WireMock returns 404 by default for unmatched requests
        Response response = client.fetchTestData("nonexistent-mock-id-xyz-404");

        // WireMock returns 404 for unmatched stubs
        assertThat(response.getStatusCode(), greaterThanOrEqualTo(400));
    }

    @Test
    @DisplayName("POST /post — server error 500 is handled gracefully")
    void submitTestData_serverError_returns500() {
        stubFor(WireMock.post(WireMock.urlEqualTo("/post"))
                .willReturn(WireMock.aResponse()
                        .withStatus(500)
                        .withHeader("Content-Type", "application/json")
                        .withBody("{\"error\": \"Internal Server Error\"}")));

        MetricDetailsDto metrics = MetricDetailsDto.builder()
                .testsCount(0)
                .passRate(0.0)
                .build();

        TestPayloadInputDto payload = TestPayloadInputDto.builder()
                .environment("broken")
                .featuresEnabled(false)
                .metrics(metrics)
                .build();

        Response response = client.submitTestData(payload, "error-header");

        assertThat(response.getStatusCode(), org.hamcrest.Matchers.equalTo(500));
    }

    @Test
    @DisplayName("GET /get — service unavailable 503 is handled gracefully")
    void fetchTestData_serviceUnavailable_returns503() {
        stubFor(WireMock.get(WireMock.urlPathEqualTo("/get"))
                .willReturn(WireMock.aResponse()
                        .withStatus(503)
                        .withHeader("Content-Type", "application/json")
                        .withBody("{\"error\": \"Service Unavailable\"}")));

        Response response = client.fetchTestData(null);

        assertThat(response.getStatusCode(), org.hamcrest.Matchers.equalTo(503));
    }
}

